package github.chains;

import spoon.Launcher;
import spoon.reflect.CtModel;
import spoon.reflect.code.CtExpression;
import spoon.reflect.code.CtFieldRead;
import spoon.reflect.code.CtInvocation;
import spoon.reflect.declaration.CtClass;
import spoon.reflect.declaration.CtField;
import spoon.reflect.declaration.CtMethod;
import spoon.reflect.declaration.CtType;
import spoon.reflect.factory.Factory;
import spoon.reflect.reference.CtFieldReference;
import spoon.reflect.reference.CtTypeReference;
import spoon.reflect.visitor.filter.TypeFilter;
import spoon.template.Template;
import spoon.template.TemplateParameter;
import spoon.template.Substitution;

import java.io.File;
import java.util.List;

public class Main {
    public static void main(String[] args) {
        // Create a Spoon launcher
        Launcher launcher = new Launcher();
        launcher.getEnvironment().setComplianceLevel(8);

        // Set the source directory
        String sourceDirectory = "/workspace/incrementals-tools";
        if (args.length > 0) {
            sourceDirectory = args[0];
        }

        launcher.addInputResource(sourceDirectory);
        launcher.setSourceOutputDirectory("/tmp/spooned");

        // Process the code
        CtModel model = launcher.buildModel();

        // Find all instances of the problematic pattern
        // Pattern: GHCompare.Status status = ... .getCompare(...).status;
        // This will match field accesses to 'status' on GHCompare objects

        // Find all field reads on GHCompare.Status
        List<CtFieldRead> fieldReads = model.getElements(new TypeFilter<>(CtFieldRead.class));

        for (CtFieldRead fieldRead : fieldReads) {
            // Check if this is accessing the 'status' field on GHCompare
            if (fieldRead.getVariable() != null && 
                fieldRead.getVariable().getSimpleName().equals("status")) {

                // Get the expression that contains the field read
                CtExpression<?> expression = fieldRead.getParent(CtExpression.class);

                // Check if it's a field read on a GHCompare object
                if (expression != null && 
                    expression.getType() != null && 
                    expression.getType().getQualifiedName().contains("GHCompare")) {

                    // This is our target pattern - we need to create a replacement
                    System.out.println("Found problematic field access to GHCompare.status: " + fieldRead);
                }
            }
        }

        // Run the transformation
        launcher.process();

        // Print the result
        System.out.println("Transformation completed on " + sourceDirectory);
    }
}

